def gen(rng, size):
    n = max(1, size)
    out = []
    depth = 0
    remaining = n
    for _ in range(n):
        remaining -= 1
        if depth == 0:
            out.append('(')
            depth += 1
        elif depth >= remaining:
            out.append(')')
            depth -= 1
        elif rng.random() < 0.5:
            out.append('(')
            depth += 1
        else:
            out.append(')')
            depth -= 1
    while depth > 0:
        out.append(')')
        depth -= 1
    return [''.join(out)]

