class Solution:
    def removeOuterParentheses(self, s):
        # Brute force: split into primitives, then strip first/last char of each.
        res = []
        depth = 0
        start = 0
        for i, ch in enumerate(s):
            depth += 1 if ch == '(' else -1
            if depth == 0:
                res.append(s[start + 1:i])
                start = i + 1
        return ''.join(res)

