class Solution:
    def removeOuterParentheses(self, s):
        out = []
        bal = 0
        for ch in s:
            if ch == '(':
                if bal >= 1:
                    out.append(ch)
                bal += 1
            else:
                bal -= 1
                if bal >= 1:
                    out.append(ch)
        return ''.join(out)

