var removeOuterParentheses = function(s) {
    const out = [];
    let bal = 0;
    for (const ch of s) {
        if (ch === '(') {
            if (bal >= 1) out.push(ch);
            bal += 1;
        } else {
            bal -= 1;
            if (bal >= 1) out.push(ch);
        }
    }
    return out.join('');
};
